import{_ as a,o as d,c as r,ai as e}from"./chunks/framework.SowO7O0D.js";const p=JSON.parse('{"title":"第二课：如何迈出第一步？","description":"","frontmatter":{},"headers":[],"relativePath":"guide/02-how-to-start.md","filePath":"guide/02-how-to-start.md","lastUpdated":0}'),o={name:"guide/02-how-to-start.md"};function h(n,t,l,i,s,b){return d(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="第二课-如何迈出第一步" tabindex="-1">第二课：如何迈出第一步？ <a class="header-anchor" href="#第二课-如何迈出第一步" aria-label="Permalink to “第二课：如何迈出第一步？”">​</a></h1><p>上一课我们理解了&quot;股票是什么&quot;，这一课讲<strong>实战前的准备</strong>——开户和选择券商。</p><h2 id="一、开户准备" tabindex="-1">一、开户准备 <a class="header-anchor" href="#一、开户准备" aria-label="Permalink to “一、开户准备”">​</a></h2><h3 id="需要准备什么" tabindex="-1">需要准备什么？ <a class="header-anchor" href="#需要准备什么" aria-label="Permalink to “需要准备什么？”">​</a></h3><table tabindex="0"><thead><tr><th>准备项</th><th>说明</th></tr></thead><tbody><tr><td>身份证</td><td>有效期内的居民身份证</td></tr><tr><td>银行卡</td><td>绑定三方存管，通常支持常见银行</td></tr><tr><td>手机</td><td>接收验证码、完成身份验证</td></tr><tr><td>网络</td><td>开户全程线上完成，约10-15分钟</td></tr></tbody></table><blockquote><p>💡 现在开户都是<strong>全程线上</strong>，不需要去营业部排队了。</p></blockquote><h2 id="二、选择券商" tabindex="-1">二、选择券商 <a class="header-anchor" href="#二、选择券商" aria-label="Permalink to “二、选择券商”">​</a></h2><p>国内券商有140多家，主流的选择标准：</p><h3 id="大券商-推荐新手" tabindex="-1">大券商（推荐新手） <a class="header-anchor" href="#大券商-推荐新手" aria-label="Permalink to “大券商（推荐新手）”">​</a></h3><table tabindex="0"><thead><tr><th>券商</th><th>特点</th><th>适合人群</th></tr></thead><tbody><tr><td><strong>华泰证券</strong></td><td>用户多，APP好用（涨乐财富通）</td><td>新手友好</td></tr><tr><td><strong>中信证券</strong></td><td>券商龙头，研究实力强</td><td>有追求的投资者</td></tr><tr><td><strong>国泰君安</strong></td><td>老牌大券商</td><td>稳健型</td></tr><tr><td><strong>招商证券</strong></td><td>服务好，银行背景</td><td>追求服务的用户</td></tr><tr><td><strong>银河证券</strong></td><td>佣金低，线下网点多</td><td>预算敏感型</td></tr></tbody></table><h3 id="选择券商看什么" tabindex="-1">选择券商看什么？ <a class="header-anchor" href="#选择券商看什么" aria-label="Permalink to “选择券商看什么？”">​</a></h3><ol><li><strong>APP体验</strong> — 好不好用，卡不卡顿</li><li><strong>佣金高低</strong> — 现在普遍万1~万3（后文详解）</li><li><strong>线下网点</strong> — 万一有问题能不能找到人</li><li><strong>服务质量</strong> — 研报、客服响应速度</li></ol><blockquote><p>⚠️ 不推荐小券商：App容易卡顿、服务不稳定、万一倒闭了麻烦。</p></blockquote><h2 id="三、什么是股票交易佣金" tabindex="-1">三、什么是股票交易佣金？ <a class="header-anchor" href="#三、什么是股票交易佣金" aria-label="Permalink to “三、什么是股票交易佣金？”">​</a></h2><p>券商收的手续费，就是&quot;佣金&quot;。</p><h3 id="佣金组成" tabindex="-1">佣金组成 <a class="header-anchor" href="#佣金组成" aria-label="Permalink to “佣金组成”">​</a></h3><table tabindex="0"><thead><tr><th>费用项</th><th>收费标准</th><th>归谁</th></tr></thead><tbody><tr><td>印花税</td><td>成交金额的0.05%（卖出时收）</td><td>国家</td></tr><tr><td>过户费</td><td>成交金额的0.001%（双向）</td><td>交易所</td></tr><tr><td>佣金</td><td>最高不超过成交金额的0.3%（双向）</td><td>券商</td></tr></tbody></table><h3 id="举例说明" tabindex="-1">举例说明 <a class="header-anchor" href="#举例说明" aria-label="Permalink to “举例说明”">​</a></h3><p>你买了1万元股票（单边），又卖掉了：</p><table tabindex="0"><thead><tr><th>费用</th><th>计算</th><th>金额</th></tr></thead><tbody><tr><td>印花税</td><td>10000 × 0.05%</td><td>5元（仅卖时收）</td></tr><tr><td>过户费</td><td>10000 × 0.001% × 2</td><td>0.2元</td></tr><tr><td>佣金</td><td>10000 × 0.03% × 2</td><td>6元（按万3算）</td></tr><tr><td><strong>合计</strong></td><td></td><td><strong>约11.2元</strong></td></tr></tbody></table><blockquote><p>💡 现在很多券商佣金已经降到<strong>万一</strong>甚至<strong>万0.854</strong>，开户时可以跟客户经理谈。</p></blockquote><h2 id="四、三方存管是什么" tabindex="-1">四、三方存管是什么？ <a class="header-anchor" href="#四、三方存管是什么" aria-label="Permalink to “四、三方存管是什么？”">​</a></h2><p>就是你把银行卡和证券账户绑定，钱从银行卡进证券账户，安全性由银行保障。</p><blockquote><p>简单理解：你老婆（银行）管钱，你（券商）管交易，分工明确，互相监督。</p></blockquote><h2 id="五、开始炒股前要知道" tabindex="-1">五、开始炒股前要知道 <a class="header-anchor" href="#五、开始炒股前要知道" aria-label="Permalink to “五、开始炒股前要知道”">​</a></h2><h3 id="_1-模拟盘先练手" tabindex="-1">1. 模拟盘先练手 <a class="header-anchor" href="#_1-模拟盘先练手" aria-label="Permalink to “1. 模拟盘先练手”">​</a></h3><p>大多数券商APP都有模拟交易功能，先用模拟盘熟悉操作，亏了不心疼。</p><h3 id="_2-第一笔不要太多" tabindex="-1">2. 第一笔不要太多 <a class="header-anchor" href="#_2-第一笔不要太多" aria-label="Permalink to “2. 第一笔不要太多”">​</a></h3><p>建议先用<strong>1-2个月工资</strong>的金额来练手，体验一下真实涨跌的心理感受。</p><h3 id="_3-每天关注但不要每天操作" tabindex="-1">3. 每天关注但不要每天操作 <a class="header-anchor" href="#_3-每天关注但不要每天操作" aria-label="Permalink to “3. 每天关注但不要每天操作”">​</a></h3><p>每天看一下大盘走势，熟悉市场节奏。但<strong>不要频繁买卖</strong>，手续费会吃掉你的收益。</p><h2 id="六、券商app基本功能" tabindex="-1">六、券商APP基本功能 <a class="header-anchor" href="#六、券商app基本功能" aria-label="Permalink to “六、券商APP基本功能”">​</a></h2><table tabindex="0"><thead><tr><th>功能</th><th>说明</th></tr></thead><tbody><tr><td>行情</td><td>看股票实时价格、涨跌幅</td></tr><tr><td>交易</td><td>买卖股票</td></tr><tr><td>持仓</td><td>看你买了哪些股票、盈亏多少</td></tr><tr><td>银证转账</td><td>银行卡和证券账户之间转钱</td></tr><tr><td>资讯</td><td>财经新闻、上市公司公告</td></tr></tbody></table><h2 id="思考题" tabindex="-1">思考题 <a class="header-anchor" href="#思考题" aria-label="Permalink to “思考题”">​</a></h2><blockquote><p>你计划用多少钱来开始练习？为什么选择这个金额？</p></blockquote><hr><p><strong>下一课预告</strong>：开户完成、佣金也搞清楚了，接下来学习<strong>A股的交易规则</strong>——T+1、涨跌停板、交易时间。</p>',37)])])}const g=a(o,[["render",h]]);export{p as __pageData,g as default};
